using System.ComponentModel;
using System.Net.Http.Json;
using System.Text;
using System.Text.Json;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to run this agent.");

const string modelId = "gpt-4o-mini-2024-07-18";

IChatClient chatClient = new OpenAI.OpenAIClient(apiKey)
    .AsChatClient(modelId);

var notepad = new Notepad();

var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a research assistant. When the user gives you a topic:
        1. Search the web for relevant information using multiple queries.
        2. Save key findings to your notepad using the note-taking tool.
        3. After gathering enough information, produce a final summary
           that synthesizes your notes into a coherent briefing.
        Always cite the source URLs for each finding.
        """,
    name: "ResearchAgent",
    description: "An agent that researches topics by searching the web and summarizing findings.",
    tools: [
        AIFunctionFactory.Create(WebSearchTool.SearchAsync,
            name: "web_search",
            description: "Searches the web and returns a list of results with titles, URLs, and snippets."),
        AIFunctionFactory.Create(notepad.AddNote,
            name: "add_note",
            description: "Saves a research note with a title and body to the notepad for later summarization."),
        AIFunctionFactory.Create(notepad.GetNotes,
            name: "get_notes",
            description: "Retrieves all research notes saved so far."),
    ]);

Console.WriteLine("═══════════════════════════════════════");
Console.WriteLine("  Research Agent  (type 'exit' to quit)");
Console.WriteLine("═══════════════════════════════════════");

var session = await agent.CreateSessionAsync();

while (true)
{
    Console.Write("\nTopic> ");
    var topic = Console.ReadLine();
    if (string.IsNullOrWhiteSpace(topic) || topic.Equals("exit", StringComparison.OrdinalIgnoreCase))
        break;

    notepad.Clear();

    Console.WriteLine("\nResearching...\n");

    var options = new ChatClientAgentRunOptions(new ChatOptions
    {
        Temperature = 0f,
        MaxOutputTokens = 4096,
    });

    await foreach (var update in agent.RunStreamingAsync(topic, session, options))
    {
        Console.Write(update.Text);
    }

    Console.WriteLine();
}

// ---------------------------------------------------------------------------
// Tools
// ---------------------------------------------------------------------------

/// <summary>Performs web searches using the Brave Search API or falls back to a simulated search.</summary>
static class WebSearchTool
{
    private static readonly HttpClient s_http = new();

    public static async Task<IReadOnlyList<SearchResult>> SearchAsync(
        [Description("The search query to send to the web search engine.")] string query,
        [Description("Maximum number of results to return (1-10).")] int count = 5)
    {
        count = Math.Clamp(count, 1, 10);

        // Try Brave Search API if key is available
        var braveKey = Environment.GetEnvironmentVariable("BRAVE_SEARCH_API_KEY");
        if (!string.IsNullOrEmpty(braveKey))
        {
            return await BraveSearchAsync(query, count, braveKey);
        }

        // Fallback: simulated search results for demo purposes
        Console.ForegroundColor = ConsoleColor.DarkYellow;
        Console.WriteLine($"  [web_search] \"{query}\" (simulated — set BRAVE_SEARCH_API_KEY for live results)");
        Console.ResetColor();

        return [
            new($"Overview of {query} - Wikipedia",
                $"https://en.wikipedia.org/wiki/{Uri.EscapeDataString(query)}",
                $"A comprehensive overview covering the key aspects of {query}, including history, current state, and future outlook."),
            new($"{query}: Latest Developments - TechReview",
                $"https://techreview.example.com/{Uri.EscapeDataString(query.Replace(' ', '-'))}",
                $"Recent developments in {query} show significant progress in multiple areas, with experts predicting continued growth."),
            new($"Research Paper: Advances in {query}",
                $"https://arxiv.example.org/abs/{query.GetHashCode():X}",
                $"This paper surveys the current state of {query}, identifying key trends and open challenges for researchers."),
        ];
    }

    private static async Task<IReadOnlyList<SearchResult>> BraveSearchAsync(
        string query, int count, string apiKey)
    {
        Console.ForegroundColor = ConsoleColor.DarkCyan;
        Console.WriteLine($"  [web_search] \"{query}\"");
        Console.ResetColor();

        using var request = new HttpRequestMessage(HttpMethod.Get,
            $"https://api.search.brave.com/res/v1/web/search?q={Uri.EscapeDataString(query)}&count={count}");
        request.Headers.Add("X-Subscription-Token", apiKey);
        request.Headers.Add("Accept", "application/json");

        using var response = await s_http.SendAsync(request);
        response.EnsureSuccessStatusCode();

        using var doc = await JsonDocument.ParseAsync(await response.Content.ReadAsStreamAsync());
        var results = new List<SearchResult>();

        if (doc.RootElement.TryGetProperty("web", out var web)
            && web.TryGetProperty("results", out var items))
        {
            foreach (var item in items.EnumerateArray())
            {
                results.Add(new SearchResult(
                    item.GetProperty("title").GetString() ?? "",
                    item.GetProperty("url").GetString() ?? "",
                    item.GetProperty("description").GetString() ?? ""));

                if (results.Count >= count) break;
            }
        }

        return results;
    }
}

record SearchResult(string Title, string Url, string Snippet);

// ---------------------------------------------------------------------------

/// <summary>A simple in-memory notepad for the agent to store research findings.</summary>
class Notepad
{
    private readonly List<Note> _notes = [];

    public string AddNote(
        [Description("A short title for the note.")] string title,
        [Description("The body of the research note.")] string body)
    {
        _notes.Add(new Note(title, body, DateTime.UtcNow));

        Console.ForegroundColor = ConsoleColor.DarkGreen;
        Console.WriteLine($"  [add_note] \"{title}\"");
        Console.ResetColor();

        return $"Note '{title}' saved (total: {_notes.Count}).";
    }

    public IReadOnlyList<Note> GetNotes()
    {
        Console.ForegroundColor = ConsoleColor.DarkGreen;
        Console.WriteLine($"  [get_notes] returning {_notes.Count} note(s)");
        Console.ResetColor();

        return _notes.AsReadOnly();
    }

    public void Clear() => _notes.Clear();
}

record Note(string Title, string Body, DateTime SavedAtUtc);

