 /// <summary>Performs web searches using the Brave Search API or falls back to a simulated search.</summary>
 static class WebSearchTool
 {
     private static readonly HttpClient s_http = new();

     public static async Task<IReadOnlyList<SearchResult>> SearchAsync(
         [Description("The search query to send to the web search engine.")] string query,
         [Description("Maximum number of results to return (1-10).")] int count = 5)
     {
         count = Math.Clamp(count, 1, 10);

